  ('retired-7fec267e-moex-00096', 'retired-7fec267e', 'retired-7fec267e-moex-114-3a7b2121', 'sub-retired-7fec267e-05', NULL, 'single_choice', '有關政府採購契約的履約管理，下列敘述何者錯誤？', '["委託規劃設計之契約，應訂明廠商規劃設計錯誤以致機關遭受損害之責任", "得標廠商應自行履行工程、勞務契約，也可以轉包", "得標廠商得將採購分包予其他廠商", "機關辦理工程、財物採購，應限期辦理驗收，並得辦理部分驗收"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:00+00:00", "source_pdf_sha1": "c9f722da4e68", "answer_pdf_sha1": "fc489aad6334", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "131", "s": "0304", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政學", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "一般行政"}'::jsonb, NULL),
  ('retired-7fec267e-moex-00097', 'retired-7fec267e', 'retired-7fec267e-moex-114-3082b5f1', 'sub-retired-7fec267e-06', NULL, 'essay', '甲原為某市立高級中等學校主任軍訓教官，於民國（下同）110 年間對
該校乙生有霸凌行為，學校調查認定校園霸凌行為成立，提經教育部軍
訓教官人事評審會，決議核予甲撤職並停止任用1 年之懲罰，且1 年不
得介派為軍訓教官，教育部以 114 年 3 月 10 日令核定。之後教育部於
114 年 3 月 12 日函國防部參謀本部人事參謀次長室，請國防部協助
辦理甲撤職及停役相關人事作業，國防部以 114 年 5 月 20 日函核定甲
停役，並溯及自 114 年 3 月 10 日生效。試問: 114 年 3 月 12 日函與
114年5月20日函之法律性質為何?114年3月10日令對114年5月20
日函發生何種法律效力？甲若不服停役之核定，應向何機關提起訴願？
（25分）
參考條文：陸海空軍軍官士官服役條例第 14 條第 1 項第 6 款規定「常
備軍官、常備士官，在現役期間，有下列情形之一者，予以停役：六、
依法停止任用或不得再任用。」', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:00+00:00", "source_pdf_sha1": "08231c21eb42", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "131", "s": "0403", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "行政法", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": "一", "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "一般行政"}'::jsonb, NULL),
  ('retired-7fec267e-moex-00098', 'retired-7fec267e', 'retired-7fec267e-moex-114-3082b5f1', 'sub-retired-7fec267e-06', NULL, 'essay', '甲係大陸地區人民，與乙（臺灣地區人民）在大陸地區結婚，甲於民國
（下同）114 年 1月 27 日申請來臺團聚，內政部移民署北區事務大隊臺
北市專勤隊隊員丙於 114 年 2 月3 日電訪乙後，因乙在申請案中，並未
提出有效的結婚文件，電訪中說詞又有重大瑕疵，丙認為無積極事證足
認婚姻為真實，事實已經客觀明白，因此主管機關依大陸地區人民申請
進入臺灣地區面談管理辦法第 14 條第 2 款及第 4 款規定，以 A 處分書
不予許可甲申請來臺團聚。試問：乙若認為丙對其有偏見，應迴避該申
請案之處理，是否有理由？機關接受乙之迴避申請書後，應如何處理？
甲主張在來臺團聚申請案中，自己的程序參與權利受侵害，A處分書無
效，是否有理由？（25 分）
13720、30120', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:00+00:00", "source_pdf_sha1": "08231c21eb42", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "131", "s": "0403", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "行政法", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": "二", "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "一般行政"}'::jsonb, NULL),
  ('retired-7fec267e-moex-00099', 'retired-7fec267e', 'retired-7fec267e-moex-114-3082b5f1', 'sub-retired-7fec267e-06', NULL, 'single_choice', '關於行政法法源，下列敘述何者正確？', '["各種法源效力平等，無位階之分", "行政法法源不僅只有成文法法源，一般法律原則亦為法源", "行政規則之訂定屬於行政行為，不得作為行政法之法源", "僅有通過立法行為，方能產生法源"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:00+00:00", "source_pdf_sha1": "08231c21eb42", "answer_pdf_sha1": "647b6f5bbf6b", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "131", "s": "0403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "一般行政"}'::jsonb, NULL),
  ('retired-7fec267e-moex-00100', 'retired-7fec267e', 'retired-7fec267e-moex-114-3082b5f1', 'sub-retired-7fec267e-06', NULL, 'single_choice', '依司法院解釋意旨，關於層級化法律保留，下列敘述何者錯誤？', '["何種事項應以法律直接規範或得委由法規命令予以規定，與所涉權利義務有關", "若屬執行法律之細節性、技術性次要事項，則無須法律授權，得由行政機關依職權訂定行政規 則規範", "關於給付行政，法律規範密度較為寬鬆，倘涉及公共利益重大事項，仍有法律保留原則之適用", "涉及人民自由權利之限制者，如財產權，強調國會保留，即不得授權命令為補充性規範"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:00+00:00", "source_pdf_sha1": "08231c21eb42", "answer_pdf_sha1": "647b6f5bbf6b", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "131", "s": "0403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "一般行政"}'::jsonb, NULL),
  ('retired-7fec267e-moex-00101', 'retired-7fec267e', 'retired-7fec267e-moex-114-3082b5f1', 'sub-retired-7fec267e-06', NULL, 'single_choice', '關於行政裁量之敘述，下列何者錯誤？', '["社會秩序維護法第29條規定，違反本法行為之情節可憫恕者，得減輕或免除其處罰，屬於決 定裁量之範圍", "行政機關所選定之法律效果，逾越法律所授權之裁量範圍，則構成裁量逾越之瑕疵", "行政機關若消極地未斟酌具體個案情節，就作出決定，即構成裁量怠惰之瑕疵", "行政機關為裁量時，不受平等原則拘束"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:00+00:00", "source_pdf_sha1": "08231c21eb42", "answer_pdf_sha1": "647b6f5bbf6b", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "131", "s": "0403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "一般行政"}'::jsonb, NULL),
  ('retired-7fec267e-moex-00102', 'retired-7fec267e', 'retired-7fec267e-moex-114-3082b5f1', 'sub-retired-7fec267e-06', NULL, 'single_choice', '關於地方自治團體權限之敘述，下列何者錯誤？', '["地方自治團體具有財政自主權，中央不得以法律規定地方分擔基於國家整體施政所需之經費", "地方自治團體有就自治事項制定規章並執行之權限", "地方自治團體對其是否設置特定機關或事業機構，享有自主組織權", "法律規定得設置之職位，地方自治團體既有自主決定設置與否之權限，仍應有組織自治條例之 依據始得進用"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:00+00:00", "source_pdf_sha1": "08231c21eb42", "answer_pdf_sha1": "647b6f5bbf6b", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "131", "s": "0403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "一般行政"}'::jsonb, NULL),
  ('retired-7fec267e-moex-00103', 'retired-7fec267e', 'retired-7fec267e-moex-114-3082b5f1', 'sub-retired-7fec267e-06', NULL, 'single_choice', '關於行政組織之敘述，下列何者正確？', '["獨立機關是指依據法令獨立行使職權之機關", "政府與人民合資經營之事業，皆為公營事業", "依據公法所設立之組織體，皆為公法社團", "國家任務性質上不適宜由行政機關實施亦不適宜由民間實施者，得設立行政法人"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:00+00:00", "source_pdf_sha1": "08231c21eb42", "answer_pdf_sha1": "647b6f5bbf6b", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "131", "s": "0403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "一般行政"}'::jsonb, NULL),
  ('retired-7fec267e-moex-00104', 'retired-7fec267e', 'retired-7fec267e-moex-114-3082b5f1', 'sub-retired-7fec267e-06', NULL, 'single_choice', '關於行政機關管轄權之敘述，下列何者正確？', '["行政機關不得透過行政規則或與其他機關簽訂契約來變更管轄權", "無管轄權之行政機關所作成之行政處分，均為無效", "人民不服財政部中區國稅局依法所為指定管轄之決定時，得向財政部提起訴願", "經濟部依法公告委託高雄市政府辦理高雄港區內工廠設立許可、登記、管理及輔導事項，為權 限委任"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:00+00:00", "source_pdf_sha1": "08231c21eb42", "answer_pdf_sha1": "647b6f5bbf6b", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "131", "s": "0403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "一般行政"}'::jsonb, NULL),
  ('retired-7fec267e-moex-00105', 'retired-7fec267e', 'retired-7fec267e-moex-114-3082b5f1', 'sub-retired-7fec267e-06', NULL, 'single_choice', '依司法實務見解，關於公務員免職權限之敘述，下列何者正確？', '["公務員之免職為法院專屬權限", "行政機關以考績處分免除公務員之職務，牴觸憲法由司法院執掌懲戒權之規定", "公務員之免職權屬於行政機關人事權之固有核心", "對於公務員違法失職之行為，行政機關不得以考績處分處罰之"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:00+00:00", "source_pdf_sha1": "08231c21eb42", "answer_pdf_sha1": "647b6f5bbf6b", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "131", "s": "0403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "一般行政"}'::jsonb, NULL)
